import React, { useEffect, useState } from 'react';
import './UIDSILoginPage.css';
import { TelemetryCollector } from './telemetryCollector';
import { InteractionTracker } from './interactionTracker';
import { EnvironmentFingerprint } from './envFingerprint';

interface BotDetectionResult {
  risk_score: number;
  is_bot: boolean;
  recommended_action: string;
}

const UIDSILoginPage: React.FC = () => {
  const [aadharInput, setAadharInput] = useState('');
  const [captchaInput, setCaptchaInput] = useState('');
  const [captchaText, setCaptchaText] = useState('bbfd68');
  const [loginAttempts, setLoginAttempts] = useState(0);
  const [isLocked, setIsLocked] = useState(false);
  const [isChecking, setIsChecking] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const [successMessage, setSuccessMessage] = useState('');

  // Generate random CAPTCHA
  const generateCaptcha = () => {
    const chars = 'ABCDEFGHJKMNPQRSTUVWXYZabcdefghjkmnpqrstuvwxyz0123456789';
    let captcha = '';
    for (let i = 0; i < 6; i++) {
      captcha += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    setCaptchaText(captcha);
  };

  // Verify CAPTCHA
  const verifyCaptcha = () => {
    return captchaInput.toLowerCase() === captchaText.toLowerCase();
  };

  // Check for bot using ML model
  const checkIfBot = async (): Promise<BotDetectionResult> => {
    setIsChecking(true);
    try {
      const telemetryCollector = new TelemetryCollector();
      const interactionTracker = new InteractionTracker();

      const deviceFp = telemetryCollector.captureDeviceFingerprint();
      const interactions = interactionTracker.getAllSignals();
      const jitter = await EnvironmentFingerprint.measureEventLoopJitter();

      const payload = {
        telemetry: {
          device: deviceFp,
          mouse: interactions?.mouse || {},
          keyboard: interactions?.keyboard || {},
          timing: { event_loop_jitter: jitter }
        },
        session_id: 'uidai-' + Date.now()
      };

      const response = await fetch('http://localhost:8000/api/predict', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });

      if (!response.ok) throw new Error('Bot detection API failed');

      const result = await response.json();
      return {
        risk_score: result.risk_score || 50,
        is_bot: (result.risk_score || 50) > 60,
        recommended_action: result.recommended_action || 'ALLOW'
      };
    } catch (error) {
      console.error('Bot detection error:', error);
      return { risk_score: 50, is_bot: false, recommended_action: 'ALLOW' };
    } finally {
      setIsChecking(false);
    }
  };

  // Handle login
  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage('');
    setSuccessMessage('');

    if (isLocked) {
      setErrorMessage('Account locked. Too many failed attempts.');
      return;
    }

    // Admin access (special credentials)
    if (aadharInput === '37775631' && captchaInput === 'G8') {
      setSuccessMessage('✅ Admin access granted!');
      setTimeout(() => {
        window.open('/admin-dashboard', '_blank');
      }, 500);
      setAadharInput('');
      setCaptchaInput('');
      generateCaptcha();
      return;
    }

    // Validate Aadhar
    if (!aadharInput || aadharInput.length !== 12) {
      setErrorMessage('Please enter a valid 12-digit Aadhar number');
      return;
    }

    // Verify CAPTCHA
    if (!verifyCaptcha()) {
      setErrorMessage('❌ Incorrect CAPTCHA');
      setLoginAttempts(prev => prev + 1);
      generateCaptcha();
      setCaptchaInput('');
      if (loginAttempts >= 2) setIsLocked(true);
      return;
    }

    // Check for bot
    const botResult = await checkIfBot();

    if (botResult.is_bot) {
      setErrorMessage('🚫 Bot detected. Please try again with natural interactions.');
      setLoginAttempts(prev => prev + 1);
      if (loginAttempts >= 2) setIsLocked(true);
      return;
    }

    // Success
    setSuccessMessage('✅ Verification successful! Sending OTP...');
    setTimeout(() => {
      setAadharInput('');
      setCaptchaInput('');
      generateCaptcha();
      setLoginAttempts(0);
    }, 2000);
  };

  // Initialize
  useEffect(() => {
    generateCaptcha();
  }, []);

  return (
    <div className="login-page">
      {/* Header */}
      <header className="login-header">
        <div className="header-content">
          <div className="logo-section">
            <div className="logo-india">🇮🇳</div>
            <div className="header-text">
              <h1>Unique Identification Authority</h1>
              <p>myAadhaar - eAadhaar Verification</p>
            </div>
          </div>
          <div className="logo-aadhaar">🔴</div>
        </div>
      </header>

      {/* Main Content */}
      <main className="login-main">
        <div className="login-wrapper">
          {/* Form */}
          <div className="login-box">
            <h2>eAadhaar Download / Verification</h2>
            <p className="subtitle">Enter your 12-digit Aadhar Number</p>

            {errorMessage && <div className="alert alert-error">{errorMessage}</div>}
            {successMessage && <div className="alert alert-success">{successMessage}</div>}

            <form onSubmit={handleLogin} className="login-form">
              {/* Aadhar Input */}
              <div className="form-group">
                <label>Aadhar Number</label>
                <input
                  type="text"
                  placeholder="Enter 12-digit number"
                  value={aadharInput}
                  onChange={(e) => setAadharInput(e.target.value.replace(/\D/g, '').slice(0, 12))}
                  maxLength={12}
                  disabled={isLocked}
                  className="form-input"
                />
              </div>

              {/* CAPTCHA */}
              <div className="form-group">
                <label>Verification Code</label>
                <div className="captcha-row">
                  <div className="captcha-box">
                    <span className="captcha-text">{captchaText}</span>
                  </div>
                  <button
                    type="button"
                    className="captcha-refresh-btn"
                    onClick={() => {
                      generateCaptcha();
                      setCaptchaInput('');
                    }}
                    title="Refresh"
                  >
                    🔄
                  </button>
                </div>
                <input
                  type="text"
                  placeholder="Enter code"
                  value={captchaInput}
                  onChange={(e) => setCaptchaInput(e.target.value)}
                  disabled={isLocked}
                  className="form-input"
                />
              </div>

              {/* Submit */}
              <button
                type="submit"
                className={`submit-btn ${isLocked ? 'disabled' : ''}`}
                disabled={isLocked || isChecking}
              >
                {isChecking ? '⏳ Verifying...' : '📤 Send OTP'}
              </button>

              {isLocked && <p className="error-small">🔒 Account temporarily locked</p>}
              {loginAttempts > 0 && loginAttempts < 3 && (
                <p className="warning-small">⚠️ Attempts left: {3 - loginAttempts}</p>
              )}
            </form>

            {/* Info Box */}
            <div className="info-box">
              <p>🛡️ <strong>Passive Bot Detection Active</strong></p>
              <p className="info-text">Your interactions are being analyzed to verify you're human.</p>
            </div>
          </div>

          {/* FAQ Sidebar */}
          <div className="faq-box">
            <h3>❓ Help</h3>
            <details>
              <summary>What is e-Aadhar?</summary>
              <p>Electronic version of your Aadhar document</p>
            </details>
            <details>
              <summary>Why bot detection?</summary>
              <p>Protects your identity from unauthorized access</p>
            </details>
            <details>
              <summary>Is data safe?</summary>
              <p>Yes. No personal data is stored unnecessarily.</p>
            </details>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="login-footer">
        <p>© 2026 Unique Identification Authority of India. All rights reserved.</p>
      </footer>
    </div>
  );
};

export default UIDSILoginPage;
